<?php
namespace app\Middleware; use app\Helpers\ApiResponse; use app\Repositories\UserRepository;
class AuthMiddleware{ public static function requireLogin():array{ $h=function_exists('getallheaders')?getallheaders():[]; $token=''; if(!empty($h['Authorization'])) $token=trim(str_replace('Bearer','',$h['Authorization'])); elseif(!empty($_SESSION['api_token'])) $token=$_SESSION['api_token']; if(!$token) ApiResponse::error('Bạn chưa đăng nhập API',[],401); $u=(new UserRepository())->findByApiToken($token); if(!$u) ApiResponse::error('Token không hợp lệ hoặc đã đăng xuất',[],401); return $u; } public static function requireAdmin():array{ $u=self::requireLogin(); if(($u['role_name']??'')!=='admin') ApiResponse::error('Bạn không có quyền thực hiện thao tác này',[],403); return $u; }}
